/**
 * TownSystem — Town generation, shop inventory, inn resting, NPC hiring, and haggling.
 * All town archetype data is JSON-driven from towns.json and hireable_npcs.json.
 *
 * @module TownSystem
 */

import DebugLog from '../debug/DebugLog.js';
import TOWNS_DATA from '../data/towns.json';
import HIREABLE_NPCS_DATA from '../data/hireable_npcs.json';
import ItemSystem from './ItemSystem.js';
import CharacterSystem from './CharacterSystem.js';
import WorldState from '../world/WorldState.js';
import { createRNG } from '../utils/RNG.js';

// ─── Shop type → item type/subtype mapping ────────────────────────────────────

/**
 * Maps shop type to the item types/subtypes that shop stocks.
 * Each entry: { types: string[], subtypes: string[], slots: string[] }
 */
const SHOP_ITEM_POOLS = {
  weapon_shop: {
    types: ['weapon'],
    subtypes: ['sword', 'axe', 'dagger', 'spear', 'hammer', 'maul', 'bow', 'staff', 'wand'],
    slots: ['weapon'],
    stockCount: [6, 10],
  },
  armor_shop: {
    types: ['armor', 'shield'],
    subtypes: ['robe', 'leather', 'chainmail', 'plate', 'buckler', 'shield', 'tower_shield'],
    slots: ['armor', 'offhand', 'helmet', 'boots', 'gloves', 'belt'],
    stockCount: [6, 10],
  },
  supply_shop: {
    types: ['consumable', 'tool'],
    subtypes: ['potion', 'food', 'gear', 'scroll', 'tool'],
    slots: [],
    stockCount: [8, 14],
  },
  arcane_shop: {
    types: ['weapon', 'offhand', 'consumable'],
    subtypes: ['staff', 'wand', 'orb', 'scroll', 'potion'],
    slots: ['weapon', 'offhand'],
    stockCount: [5, 8],
  },
  black_market: {
    types: ['weapon', 'consumable', 'tool'],
    subtypes: ['dagger', 'bow', 'potion', 'gear', 'tool'],
    slots: ['weapon'],
    stockCount: [4, 7],
  },
  trade_post: {
    types: ['consumable', 'tool'],
    subtypes: ['food', 'gear', 'tool'],
    slots: [],
    stockCount: [8, 12],
  },
  blacksmith: {
    types: ['weapon', 'armor', 'shield'],
    subtypes: ['sword', 'axe', 'hammer', 'maul', 'chainmail', 'plate', 'shield', 'tower_shield'],
    slots: ['weapon', 'armor', 'offhand'],
    stockCount: [4, 8],
  },
};

// ─── Base item pricing by type ────────────────────────────────────────────────

const BASE_PRICES = {
  weapon:     { base: 30, perLevel: 15 },
  armor:      { base: 25, perLevel: 12 },
  shield:     { base: 20, perLevel: 10 },
  offhand:    { base: 15, perLevel: 8 },
  accessory:  { base: 20, perLevel: 10 },
  consumable: { base: 8,  perLevel: 4 },
  tool:       { base: 12, perLevel: 5 },
};

const RARITY_PRICE_MULTIPLIERS = {
  common:    1.0,
  magic:     2.0,
  rare:      4.0,
  legendary: 10.0,
  unique:    20.0,
};

// ─── Inn cost scaling ─────────────────────────────────────────────────────────

const INN_COST_PER_LEVEL = 3;
const MAX_PARTY_SIZE = 4;

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Derive a shop-sell price for an item instance.
 * @param {object} baseItem
 * @returns {number}
 */
function deriveItemPrice(baseItem) {
  const priceData = BASE_PRICES[baseItem.type] ?? BASE_PRICES.consumable;
  const level = baseItem.level ?? 1;
  const rarity = baseItem.rarity ?? 'common';
  const rarityMult = RARITY_PRICE_MULTIPLIERS[rarity] ?? 1.0;
  return Math.max(1, Math.round((priceData.base + (level - 1) * priceData.perLevel) * rarityMult));
}

/**
 * Check whether an item's subtype matches a bias list entry.
 * Bias entries can be subtype names (e.g. "sword") or armor class names (e.g. "medium_armor").
 * @param {object} baseItem
 * @param {string[]} biases
 * @returns {boolean}
 */
function itemMatchesBias(baseItem, biases) {
  if (!biases || biases.length === 0) return false;
  const subtype = baseItem.subtype ?? '';
  const armorClass = baseItem.armorClass ?? '';
  return biases.some(b => subtype === b || armorClass === b || subtype.includes(b) || b.includes(subtype));
}

// ─── TownSystem ───────────────────────────────────────────────────────────────

const TownSystem = {
  /** @type {Map<string, object>} Cached town archetypes keyed by id */
  _archetypes: new Map(),

  /** @type {boolean} */
  _initialized: false,

  /**
   * Initialize TownSystem — loads archetype data into memory.
   * Safe to call multiple times.
   */
  init() {
    if (this._initialized) return;

    for (const archetype of TOWNS_DATA) {
      this._archetypes.set(archetype.id, Object.freeze({ ...archetype }));
    }

    this._initialized = true;
    DebugLog.info(`[town] TownSystem initialized; archetypes=${this._archetypes.size}`);
  },

  // ─── Archetype queries ────────────────────────────────────────────────────

  /**
   * Get a town archetype definition by id.
   * @param {string} townTypeId
   * @returns {object|null}
   */
  getArchetype(townTypeId) {
    const archetype = this._archetypes.get(townTypeId);
    if (!archetype) {
      DebugLog.warn(`[town] getArchetype: unknown townTypeId "${townTypeId}"`);
      return null;
    }
    return archetype;
  },

  /**
   * Get all town archetype definitions.
   * @returns {object[]}
   */
  getAllArchetypes() {
    return [...this._archetypes.values()];
  },

  // ─── Town generation ──────────────────────────────────────────────────────

  /**
   * Generate a town instance from world generation data.
   * Produces a runtime town object with shops, hireable NPCs, and inn quests.
   *
   * @param {object} townData — From WorldGenerator: { townType, name, level, id, regionId }
   * @param {number} worldSeed
   * @returns {object} Town instance
   */
  generateTown(townData, worldSeed) {
    const archetype = this.getArchetype(townData.townType ?? 'human_town');
    if (!archetype) {
      DebugLog.error(`[town] generateTown: unknown townType "${townData.townType}"`);
      return null;
    }

    const townSeed = (worldSeed ^ (townData.id ?? 0) ^ 0x6A4B3C2D) >>> 0;
    const rng = createRNG(townSeed);
    const level = townData.level ?? 1;

    // Generate shops with their initial inventory
    const shops = {};
    for (const shopType of archetype.shops) {
      shops[shopType] = this.getShopInventory(shopType, { ...townData, archetype }, level, rng.fork());
    }

    const town = {
      id: townData.id ?? `town_${Date.now().toString(36)}`,
      name: townData.name ?? archetype.name,
      townType: townData.townType ?? 'human_town',
      race: archetype.race,
      level,
      regionId: townData.regionId ?? null,
      archetype: archetype.id,
      shops,
      availableShops: [...archetype.shops],
      innCost: (archetype.innCostBase ?? 10) + (level - 1) * INN_COST_PER_LEVEL,
      requiredFame: archetype.requiredFame ?? -500,
      requiredFameMax: archetype.requiredFameMax ?? 1000,
      shopPriceModifier: archetype.shopPriceModifier ?? 1.0,
      seed: townSeed,
    };

    DebugLog.info(
      `[town] Generated town; name="${town.name}" type=${town.townType} ` +
      `level=${level} shops=${archetype.shops.length}`
    );

    return town;
  },

  // ─── Shop inventory ───────────────────────────────────────────────────────

  /**
   * Get shop inventory for a shop type in a given town.
   * Scales item levels to regionLevel. Applies racial biases (biased items appear more often).
   *
   * @param {string} shopType
   * @param {object} town — Town instance (or townData with archetype)
   * @param {number} regionLevel
   * @param {object} rng
   * @returns {Array<{itemId: string, instance: object, qty: number, price: number}>}
   */
  getShopInventory(shopType, town, regionLevel, rng) {
    if (!ItemSystem._initialized) {
      DebugLog.warn('[town] getShopInventory: ItemSystem not initialized');
    }

    const pool = SHOP_ITEM_POOLS[shopType];
    if (!pool) {
      DebugLog.warn(`[town] getShopInventory: unknown shopType "${shopType}"`);
      return [];
    }

    const archetypeId = town.archetype ?? town.townType ?? 'human_town';
    const archetype = this.getArchetype(archetypeId);
    const biases = archetype?.biases?.[shopType] ?? [];
    const priceModifier = town.shopPriceModifier ?? archetype?.shopPriceModifier ?? 1.0;

    // Build candidate item pool from ItemSystem
    const allItems = [...ItemSystem._items.values()];
    const levelMin = Math.max(1, regionLevel - 2);
    const levelMax = regionLevel + 1;

    let candidates = allItems.filter(item => {
      const itemLevel = item.level ?? 1;
      if (itemLevel < levelMin || itemLevel > levelMax) return false;

      // Check type or subtype match
      const typeMatch = pool.types.includes(item.type);
      const subtypeMatch = pool.subtypes.includes(item.subtype ?? '');
      const slotMatch = pool.slots.length === 0 || pool.slots.includes(item.slot ?? '');

      return (typeMatch || subtypeMatch) && (pool.slots.length === 0 || slotMatch);
    });

    if (candidates.length === 0) {
      DebugLog.warn(`[town] getShopInventory: no items found for shopType="${shopType}" level=${regionLevel}`);
      return [];
    }

    // Build weighted candidate list — biased items appear 3x more often
    const weighted = [];
    for (const item of candidates) {
      const weight = itemMatchesBias(item, biases) ? 3 : 1;
      for (let w = 0; w < weight; w++) {
        weighted.push(item);
      }
    }

    const [minStock, maxStock] = pool.stockCount;
    const stockCount = rng.nextInt(minStock, maxStock);

    const inventory = [];
    const usedIds = new Set();

    for (let i = 0; i < stockCount; i++) {
      const baseItem = rng.pick(weighted);
      if (!baseItem) continue;

      // Allow stackables to appear multiple times, deduplicate gear
      if (!baseItem.stackable && usedIds.has(baseItem.id)) continue;
      usedIds.add(baseItem.id);

      // Roll rarity — higher level towns have better chances for magic/rare
      const rarityRoll = rng.nextFloat();
      let rarity = 'common';
      const rareChance    = Math.min(0.05 + regionLevel * 0.01, 0.20);
      const magicChance   = Math.min(0.15 + regionLevel * 0.02, 0.40);
      if (rarityRoll < rareChance)        rarity = 'rare';
      else if (rarityRoll < magicChance)  rarity = 'magic';

      const instance = ItemSystem.createInstance(baseItem.id, {
        rarity,
        level: baseItem.level ?? 1,
        identified: true,
      });
      if (!instance) continue;

      const basePrice = deriveItemPrice(baseItem);
      const rarityMult = RARITY_PRICE_MULTIPLIERS[rarity] ?? 1.0;
      const price = Math.max(1, Math.round(basePrice * rarityMult * priceModifier));

      const qty = baseItem.stackable ? rng.nextInt(3, 12) : 1;

      inventory.push({
        itemId: baseItem.id,
        instance,
        qty,
        price,
      });
    }

    return inventory;
  },

  // ─── Inn ──────────────────────────────────────────────────────────────────

  /**
   * Rest at the inn. Heals all party characters to full HP and full Mana.
   * Costs gold based on town inn cost and party size.
   *
   * @param {Array} partyChars — Array of character objects
   * @returns {{ success: boolean, goldCost: number, message: string }}
   */
  restAtInn(partyChars) {
    const town = WorldState.currentTown;
    if (!town) {
      return { success: false, goldCost: 0, message: 'You are not in a town.' };
    }

    if (!town.availableShops?.includes('inn')) {
      return { success: false, goldCost: 0, message: 'This town has no inn.' };
    }

    const partySize = Math.max(1, partyChars?.length ?? 1);
    const costPerPerson = town.innCost ?? 10;
    const goldCost = costPerPerson * partySize;

    if (WorldState.partyGold < goldCost) {
      return {
        success: false,
        goldCost,
        message: `Not enough gold. Resting costs ${goldCost} gold (${costPerPerson} per person).`,
      };
    }

    WorldState.partyGold -= goldCost;

    // Heal all party members
    let healedCount = 0;
    if (partyChars) {
      for (const char of partyChars) {
        if (char.hp < char.maxHP || char.mana < char.maxMana) {
          char.hp   = char.maxHP;
          char.mana = char.maxMana;
          // Clear minor status effects that rest would cure
          char.statusEffects = (char.statusEffects ?? []).filter(
            s => (typeof s === 'string' ? s : s.id) === 'curse' // curses persist through rest
          );
          healedCount++;
        }
      }
    }

    DebugLog.event(
      `[town] Inn rest; town=${town.name} cost=${goldCost} partySize=${partySize} ` +
      `healedCount=${healedCount} goldRemaining=${WorldState.partyGold}`
    );

    return {
      success: true,
      goldCost,
      message: `The party rests at the inn. (${goldCost} gold) All wounds are healed.`,
    };
  },

  // ─── Hireable NPCs ────────────────────────────────────────────────────────

  /**
   * Get the list of hireable NPCs available at this town's tavern.
   * Level-scaled to regionLevel ± 2. Returns 4–6 unique NPC instances.
   *
   * @param {object} town — Town instance
   * @param {number} regionLevel
   * @param {object} rng
   * @returns {Array<object>} NPC character instances ready to hire
   */
  getHireableNPCs(town, regionLevel, rng) {
    if (!town.availableShops?.includes('tavern')) {
      return [];
    }

    const archetype = this.getArchetype(town.archetype ?? town.townType ?? 'human_town');
    const [minCount, maxCount] = archetype?.tavernHireCount ?? [4, 6];
    const count = rng.nextInt(minCount, maxCount);

    const levelMin = Math.max(1, regionLevel - 2);
    const levelMax = regionLevel + 2;

    // Filter hireable NPC pool to appropriate base levels
    const eligible = HIREABLE_NPCS_DATA.filter(npc => {
      const npcLevel = npc.baseLevel ?? 1;
      return npcLevel <= regionLevel + 1;
    });

    if (eligible.length === 0) {
      DebugLog.warn(`[town] getHireableNPCs: no eligible NPCs for regionLevel=${regionLevel}`);
      return [];
    }

    const shuffled = rng.shuffle([...eligible]);
    const selected = shuffled.slice(0, Math.min(count, shuffled.length));

    const townSeed = town.seed ?? Date.now();
    const npcs = selected.map((template, idx) => {
      const npcLevel = Math.min(
        Math.max(levelMin, template.baseLevel ?? 1),
        levelMax
      );

      // Create a proper NPC character instance via CharacterSystem
      const npcChar = CharacterSystem.createNPC({
        level: npcLevel,
      });

      // Override with template-specific data
      npcChar.name             = template.name;
      npcChar.class            = template.class;
      npcChar.portrait         = template.portrait ?? null;
      npcChar.wagePerDay       = Math.max(1, (template.wagePerDay ?? 5) + Math.floor((npcLevel - 1) * 1.5));
      npcChar.hireableTemplate = template.id;
      npcChar.isHero           = false;

      // Apply template base stats as a seed for attributes, scaled to level
      if (template.stats) {
        const levelBonus = Math.floor((npcLevel - 1) * 0.5);
        for (const [attr, val] of Object.entries(template.stats)) {
          if (attr in (npcChar.attributes ?? {})) {
            npcChar.attributes[attr] = Math.min(20, val + levelBonus);
          }
        }
        // Recompute derived stats after overriding attributes
        npcChar.maxHP   = CharacterSystem.computeMaxHP(npcChar);
        npcChar.hp      = npcChar.maxHP;
        npcChar.maxMana = CharacterSystem.computeMaxMana(npcChar);
        npcChar.mana    = npcChar.maxMana;
      }

      DebugLog.info(
        `[town] Hireable NPC generated; name=${npcChar.name} class=${npcChar.class} ` +
        `level=${npcLevel} wage=${npcChar.wagePerDay}`
      );

      return npcChar;
    });

    return npcs;
  },

  // ─── NPC Hiring ───────────────────────────────────────────────────────────

  /**
   * Hire an NPC and add them to the party.
   * Party maximum is 4 characters. Deducts the first day's wage.
   *
   * @param {object} npc — NPC character object (from getHireableNPCs)
   * @param {Array} currentParty — Current party character array
   * @returns {{ success: boolean, message: string }}
   */
  hireNPC(npc, currentParty) {
    if (!npc) {
      return { success: false, message: 'No NPC provided.' };
    }

    if (!currentParty) {
      return { success: false, message: 'No party provided.' };
    }

    if (currentParty.length >= MAX_PARTY_SIZE) {
      return {
        success: false,
        message: `Party is full (maximum ${MAX_PARTY_SIZE} characters).`,
      };
    }

    const firstDayWage = npc.wagePerDay ?? 5;
    if (WorldState.partyGold < firstDayWage) {
      return {
        success: false,
        message: `Not enough gold to hire ${npc.name}. First day's wage: ${firstDayWage} gold.`,
      };
    }

    WorldState.partyGold -= firstDayWage;
    currentParty.push(npc);

    DebugLog.event(
      `[town] NPC hired; name=${npc.name} class=${npc.class} ` +
      `level=${npc.level} wage=${npc.wagePerDay} goldRemaining=${WorldState.partyGold}`
    );

    return {
      success: true,
      message: `${npc.name} has joined the party. (${firstDayWage} gold first day's wage)`,
    };
  },

  // ─── Haggling ────────────────────────────────────────────────────────────

  /**
   * Attempt to haggle at a vendor for a discount.
   * Uses a Presence check: d20 + presenceMod vs DC (8 + regionLevel).
   * Can only be attempted once per vendor per in-game day.
   *
   * @param {object} character — The character attempting to haggle
   * @param {string} shopType — The shop type being haggled at
   * @param {number} regionLevel
   * @param {object} rng
   * @returns {{ success: boolean, discount: number, message: string }}
   */
  haggle(character, shopType, regionLevel, rng) {
    if (!character) {
      return { success: false, discount: 0, message: 'No character provided.' };
    }

    // Check if already haggled today at this shop
    const haggledKey = `${shopType}`;
    if (WorldState.haggledToday?.[haggledKey]) {
      return {
        success: false,
        discount: 0,
        message: 'You have already tried haggling here today.',
      };
    }

    // Mark haggle attempt for today
    if (!WorldState.haggledToday) WorldState.haggledToday = {};
    WorldState.haggledToday[haggledKey] = true;

    // Presence modifier (D&D formula)
    const presence = character.attributes?.presence ?? 10;
    const presenceMod = CharacterSystem.getAttributeModifier(presence);

    // Roll d20
    const roll = rng.nextInt(1, 20);
    const total = roll + presenceMod;
    const dc = 8 + regionLevel;

    DebugLog.event(
      `[town] Haggle attempt; character=${character.name} roll=${roll} ` +
      `presMod=${presenceMod} total=${total} dc=${dc} shop=${shopType}`
    );

    if (total >= dc) {
      // Success: 5–20% discount depending on how well they beat the DC
      const margin = total - dc;
      const discount = Math.min(0.20, 0.05 + margin * 0.015);
      const discountPct = Math.round(discount * 100);

      return {
        success: true,
        discount,
        message: `${character.name} convinces the merchant for a ${discountPct}% discount! (rolled ${roll}+${presenceMod}=${total} vs DC${dc})`,
      };
    }

    // Failure
    return {
      success: false,
      discount: 0,
      message: `${character.name} fails to haggle. (rolled ${roll}+${presenceMod}=${total} vs DC${dc})`,
    };
  },

  // ─── Blacksmith ───────────────────────────────────────────────────────────

  /**
   * Get blacksmith repair and upgrade options for all party items.
   * Returns a list of items that can be repaired, with repair cost.
   *
   * @param {Array} partyChars — Array of character objects
   * @returns {Array<{ character: object, item: object, repairCost: number, upgradeCost: number|null }>}
   */
  getBlacksmithOptions(partyChars) {
    const options = [];

    if (!partyChars || partyChars.length === 0) return options;

    for (const character of partyChars) {
      // Check inventory items
      const allItems = [
        ...(character.inventory ?? []),
        ...Object.values(character.equipment ?? {}).filter(Boolean),
      ];

      for (const item of allItems) {
        if (!item || item.durability == null || item.maxDurability == null) continue;

        const isFullyRepaired = item.durability >= item.maxDurability;
        const baseItem = ItemSystem.getBaseItem(item.baseId);
        if (!baseItem) continue;

        // Only weapons and armor are blacksmith items
        if (!['weapon', 'armor', 'shield'].includes(baseItem.type)) continue;

        const basePrice = deriveItemPrice(baseItem);
        const damageRatio = 1 - (item.durability / item.maxDurability);
        const repairCost = isFullyRepaired
          ? 0
          : Math.max(1, Math.round(basePrice * damageRatio * 0.4));

        // Upgrade cost: 50% of item value (only for common/magic items)
        const canUpgrade = ['common', 'magic'].includes(item.rarity);
        const upgradeCost = canUpgrade ? Math.round(basePrice * 0.5) : null;

        options.push({
          character,
          item,
          repairCost,
          upgradeCost,
          isFullyRepaired,
        });
      }
    }

    return options;
  },

  /**
   * Repair an item at the blacksmith.
   * Restores the item's durability to max. Costs gold based on damage level.
   *
   * @param {object} character — Character who owns the item
   * @param {string} instanceId — The item instance ID to repair
   * @returns {{ success: boolean, goldCost: number, message: string }}
   */
  repairItem(character, instanceId) {
    if (!character) {
      return { success: false, goldCost: 0, message: 'No character provided.' };
    }

    const town = WorldState.currentTown;
    if (!town?.availableShops?.includes('blacksmith')) {
      return { success: false, goldCost: 0, message: 'No blacksmith available here.' };
    }

    // Find the item in the character's possession
    const allItems = [
      ...(character.inventory ?? []),
      ...Object.values(character.equipment ?? {}).filter(Boolean),
    ];
    const item = allItems.find(i => i?.instanceId === instanceId);

    if (!item) {
      return { success: false, goldCost: 0, message: 'Item not found in character inventory or equipment.' };
    }

    if (item.durability >= item.maxDurability) {
      return { success: false, goldCost: 0, message: `${item.name} is already in perfect condition.` };
    }

    const baseItem = ItemSystem.getBaseItem(item.baseId);
    if (!baseItem) {
      return { success: false, goldCost: 0, message: 'Unknown item type.' };
    }

    const basePrice = deriveItemPrice(baseItem);
    const damageRatio = 1 - (item.durability / item.maxDurability);
    const goldCost = Math.max(1, Math.round(basePrice * damageRatio * 0.4));

    if (WorldState.partyGold < goldCost) {
      return {
        success: false,
        goldCost,
        message: `Not enough gold. Repair costs ${goldCost} gold.`,
      };
    }

    WorldState.partyGold -= goldCost;
    const oldDurability = item.durability;
    item.durability = item.maxDurability;

    DebugLog.event(
      `[town] Item repaired; item=${item.instanceId} name=${item.name} ` +
      `durability=${oldDurability}->${item.maxDurability} cost=${goldCost}`
    );

    return {
      success: true,
      goldCost,
      message: `${item.name} repaired to full durability. (${goldCost} gold)`,
    };
  },

  // ─── Fame check ───────────────────────────────────────────────────────────

  /**
   * Check if the party has sufficient fame to enter a town.
   * @param {object} town — Town instance or archetype
   * @param {number} [fame] — Party fame; defaults to WorldState.partyFame
   * @returns {{ allowed: boolean, reason: string|null }}
   */
  canEnterTown(town, fame) {
    const partyFame = fame ?? WorldState.partyFame;
    const minFame = town.requiredFame ?? -500;
    const maxFame = town.requiredFameMax ?? 1000;

    if (partyFame < minFame) {
      return {
        allowed: false,
        reason: `Your fame (${partyFame}) is too low to enter this town. Minimum: ${minFame}.`,
      };
    }

    if (partyFame > maxFame) {
      return {
        allowed: false,
        reason: `Your reputation is too honorable to be welcome in this place.`,
      };
    }

    return { allowed: true, reason: null };
  },
};

export default TownSystem;
